    foreach (cs_item_q[i, j]) begin
      `uvm_info(`gfn, $sformatf("cs_item_q[%0d][%0d]: %s",
                                i, j, cs_item_q[i][j].convert2string()),
                UVM_DEBUG)
    end
  endfunction

  virtual task csrng_set_enable(bit enable);
    mubi4_t mubi_en = prim_mubi_pkg::mubi4_bool_to_mubi(enable);

