      for (int i = 0; i < NUM_HW_APPS + 1; i++) begin
        cfg.check_internal_state(.app(i), .compare(1));
        if (!uninstantiate[i]) begin
          cs_item = new();
          `DV_CHECK_RANDOMIZE_WITH_FATAL(cs_item,
                                         cs_item.acmd  == csrng_pkg::UNI;
                                         cs_item.clen  == 'h0;)
          send_cmd_req(.app(i), .cs_item(cs_item));
        end
      end
    end
  endtask : body
