package csrng_pkg;

  // Main design parameters
  // We use the suffix 'Len' (as opposed to 'Width') to stick to the symbols used in the
  // NIST SP 800-90A algorithm specification.

  // Size of the generated random number blocks in bits and the internal state variable 'v'
  parameter int unsigned BlkLen = 128;
  // Cipher key size in bits
  parameter int unsigned KeyLen = 256;
  // Seed size in bits; must be equal to the sum of BlkLen and KeyLen
  parameter int unsigned SeedLen = BlkLen + KeyLen;
  // Width of the counter field used as input to the cipher
  // Caution: Not to be confused with the reseed counter width! These two are independent
  parameter int unsigned CtrLen = 32;

  parameter int unsigned RsCtrWidth = 32;

  // Commonly used internal signal widths
  parameter int unsigned CmdWidth = 3;
  parameter int unsigned InstIdWidth = 4;

  // Width of the application command bus (matches the 32b TLUL bus width)
  parameter int unsigned CmdBusWidth = 32;
  // Maximum number of 32b words additionally supplied on the application interfaces
  parameter int unsigned CmdMaxClen = 12;
  parameter int unsigned CmdFifoDepth = 2;

  //-------------------------
  // Application Interfaces
  //-------------------------

  parameter int unsigned GENBITS_BUS_WIDTH = 128;
  parameter int unsigned CSRNG_CMD_WIDTH = 32;
  parameter int unsigned FIPS_GENBITS_BUS_WIDTH = entropy_src_pkg::FIPS_BUS_WIDTH +
                         GENBITS_BUS_WIDTH;
  parameter int unsigned MainSmStateWidth = 8;
  parameter int unsigned CSRNG_CMD_STS_WIDTH = 3;

  // instantiation interface
  typedef struct packed {
    logic                       csrng_req_valid;
    logic [CSRNG_CMD_WIDTH-1:0] csrng_req_bus;
    logic                       genbits_ready;
  } csrng_req_t;

  typedef enum logic [CSRNG_CMD_STS_WIDTH-1:0] {
    CMD_STS_SUCCESS              = 'h0,
    CMD_STS_INVALID_ACMD         = 'h1,
    CMD_STS_INVALID_GEN_CMD      = 'h2,
    CMD_STS_INVALID_CMD_SEQ      = 'h3,
    CMD_STS_RESEED_CNT_EXCEEDED  = 'h4,
    CMD_STS_UNDRIVEN             = 'z
  } csrng_cmd_sts_e;

  typedef struct packed {
    logic                         csrng_req_ready;
    logic                         csrng_rsp_ack;
    csrng_cmd_sts_e               csrng_rsp_sts;
    logic                         genbits_valid;
    logic                         genbits_fips;
    logic [GENBITS_BUS_WIDTH-1:0] genbits_bus;
  } csrng_rsp_t;

  parameter csrng_req_t CSRNG_REQ_DEFAULT = '{default: '0};
  parameter csrng_rsp_t CSRNG_RSP_DEFAULT = '0;

  typedef enum logic [2:0] {
    INV  = 3'h0,
    INS  = 3'h1,
    RES  = 3'h2,
    GEN  = 3'h3,
    UPD  = 3'h4,
    UNI  = 3'h5,
    GENB = 3'h6,
    GENU = 3'h7
  } acmd_e;

  typedef struct packed {
    logic [7:0]       resv;
    logic [11:0]      glen;
    logic [3:0]       flag0;
    logic [3:0]       clen;
    logic             gap; // acmd is defined as 4 bits wide but only 3 are used
    acmd_e            acmd;
  } csrng_cmd_t;

  typedef struct packed {
    logic [InstIdWidth-1:0] inst_id;
    logic    [CmdWidth-1:0] cmd;
    logic      [KeyLen-1:0] key;
    logic      [BlkLen-1:0] v;
    logic     [SeedLen-1:0] pdata;
    logic  [RsCtrWidth-1:0] rs_ctr;
    logic                   fips;
  } csrng_core_data_t;

  typedef struct packed {
    logic [InstIdWidth-1:0] inst_id;
    logic    [CmdWidth-1:0] cmd;
    logic      [KeyLen-1:0] key;
    logic      [BlkLen-1:0] v;
    logic     [SeedLen-1:0] pdata;
  } csrng_upd_data_t;

  parameter int unsigned CoreDataWidth = $bits(csrng_core_data_t);
  parameter int unsigned UpdDataWidth  = $bits(csrng_upd_data_t);

  // Encoding generated with:
  // $ ./util/design/sparse-fsm-encode.py -d 3 -m 15 -n 8 \
  //      -s 1300573258 --language=sv
  //
  // Hamming distance histogram:
  //
  //  0: --
  //  1: --
  //  2: --
  //  3: |||||||||||||||||| (32.38%)
  //  4: |||||||||||||||||||| (35.24%)
  //  5: |||||||| (15.24%)
  //  6: |||||| (11.43%)
  //  7: ||| (5.71%)
  //  8: --
  //
  // Minimum Hamming distance: 3
  // Maximum Hamming distance: 7
  // Minimum Hamming weight: 1
  // Maximum Hamming weight: 7
  //
  typedef enum logic [MainSmStateWidth-1:0] {
    MainSmIdle          = 8'b01001110, // idle
    MainSmParseCmd      = 8'b10111011, // parse the cmd
    MainSmInstantPrep   = 8'b11000001, // instantiate prep
    MainSmInstantReq    = 8'b01010100, // instantiate request (takes adata or entropy)
    MainSmReseedPrep    = 8'b11011101, // reseed prep
    MainSmReseedReq     = 8'b01011011, // reseed request (takes adata and entropy and Key,V,RC)
    MainSmGeneratePrep  = 8'b11101111, // generate request (takes adata? and Key,V,RC)
    MainSmGenerateReq   = 8'b00100100, // generate request (takes adata? and Key,V,RC)
    MainSmUpdatePrep    = 8'b00110001, // update prep
    MainSmUpdateReq     = 8'b10010000, // update request (takes adata and Key,V,RC)
    MainSmUninstantPrep = 8'b11110110, // uninstantiate prep
    MainSmUninstantReq  = 8'b01100011, // uninstantiate request
    MainSmClrAData      = 8'b00000010, // clear out the additional data packer fifo
    MainSmCmdCompWait   = 8'b10111100, // wait for command to complete
    MainSmError         = 8'b01111000  // error state, results in fatal alert
  } main_sm_state_e;

  parameter int CsKeymgrDivWidth = 384;
  typedef logic [CsKeymgrDivWidth-1:0] cs_keymgr_div_t;

endpackage : csrng_pkg

