      addr_hit[1]: begin
        reg_rdata_next[0] = intr_enable_cs_cmd_req_done_qs;
        reg_rdata_next[1] = intr_enable_cs_entropy_req_qs;
        reg_rdata_next[2] = intr_enable_cs_hw_inst_exc_qs;
